document.addEventListener("DOMContentLoaded",()=>{const menuToggle=document.getElementById('menu-toggle');const menuDrawer=document.getElementById('menu-drawer');const menuBackdrop=document.getElementById('menu-backdrop');const burger=menuToggle.querySelector('.burger');const spans=burger.querySelectorAll('span');const toggleText=menuToggle.querySelector('.toggle-text');const menuLinks=document.querySelectorAll('.menu-link');let isMenuOpen=false;function toggleMenu(){isMenuOpen=!isMenuOpen;if(isMenuOpen){menuDrawer.classList.add('open');menuBackdrop.classList.add('open');toggleText.innerText='CLOSE';spans[0].style.transform='translateY(4.5px)rotate(45deg)';spans[1].style.transform='translateY(-4.5px)rotate(-45deg)';}else{menuDrawer.classList.remove('open');menuBackdrop.classList.remove('open');toggleText.innerText='MENU';spans[0].style.transform='none';spans[1].style.transform='none';}}menuToggle.addEventListener('click',toggleMenu);if(menuBackdrop){menuBackdrop.addEventListener('click',()=>{if(isMenuOpen)toggleMenu();});}menuLinks.forEach(link=>{link.addEventListener('click',toggleMenu);});const accordions=document.querySelectorAll('.accordion-item');accordions.forEach(acc=>{const header=acc.querySelector('.accordion-header');header.addEventListener('click',()=>{accordions.forEach(item=>{if(item!==acc)item.classList.remove('active');});acc.classList.toggle('active');});});const serviceBgs=document.querySelectorAll('.service-bg');const hoverTriggers=document.querySelectorAll('.hover-trigger');hoverTriggers.forEach(trigger=>{trigger.addEventListener('mouseenter',()=>{const service=trigger.getAttribute('data-bg');serviceBgs.forEach(bg=>{if(bg.getAttribute('data-service')===service){bg.classList.add('active');}else{bg.classList.remove('active');}});});trigger.addEventListener('mouseleave',()=>{serviceBgs.forEach(bg=>bg.classList.remove('active'));});});requestAnimationFrame(()=>{if(typeof gsap!=='undefined'){gsap.registerPlugin(ScrollTrigger);const revealElements=document.querySelectorAll('.reveal');revealElements.forEach(el=>{gsap.to(el,{scrollTrigger:{trigger:el,start:"top 85%",},opacity:1,y:0,duration:1.2,ease:"power3.out"});});gsap.to('.parallax-img',{scrollTrigger:{trigger:'.philosophy-image-wrapper',start:"top bottom",end:"bottom top",scrub:true},y:"10%",ease:"none"});gsap.fromTo('.process-step',{opacity:0,y:40},{scrollTrigger:{trigger:'.process-grid',start:"top 80%"},opacity:1,y:0,duration:1,stagger:0.15,ease:"power2.out"});const track=document.getElementById('slideshow-track');const paginationContainer=document.getElementById('slideshow-pagination');if(track&&paginationContainer){const items=track.querySelectorAll('.slideshow-item');items.forEach((_,index)=>{const dot=document.createElement('div');dot.classList.add('dot');if(index===0)dot.classList.add('active');dot.addEventListener('click',()=>{const itemLeft=items[index].offsetLeft;track.scrollTo({left:itemLeft -(track.clientWidth/2)+(items[index].clientWidth/2),behavior:'smooth'});});paginationContainer.appendChild(dot);});const dots=paginationContainer.querySelectorAll('.dot');let isAutoPlaying=true;let currentIndex=0;const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){const index=Array.from(items).indexOf(entry.target);currentIndex=index;dots.forEach((dot,i)=>{dot.classList.toggle('active',i===index);});items.forEach((item,i)=>{item.classList.toggle('is-active',i===index);});}});},{root:track,rootMargin:'0px -49% 0px -49%',threshold:0});items.forEach(item=>observer.observe(item));const autoPlayInterval=setInterval(()=>{if(!isAutoPlaying)return;let nextIndex=currentIndex+1;if(nextIndex>=items.length)nextIndex=0;const itemLeft=items[nextIndex].offsetLeft;track.scrollTo({left:itemLeft -(track.clientWidth/2)+(items[nextIndex].clientWidth/2),behavior:'smooth'});},3500);track.addEventListener('mouseenter',()=>isAutoPlaying=false);track.addEventListener('mouseleave',()=>isAutoPlaying=true);track.addEventListener('touchstart',()=>isAutoPlaying=false,{passive:true});track.addEventListener('touchend',()=>{setTimeout(()=>{isAutoPlaying=true;},2000);},{passive:true});}}else{const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.style.opacity=1;entry.target.style.transform='translateY(0)';}});});document.querySelectorAll('.reveal').forEach(el=>observer.observe(el));}});const customSelects=document.getElementsByClassName("custom-select");for(let i=0;i<customSelects.length;i+=1){const [selElmnt]=customSelects[i].getElementsByTagName("select");const a=document.createElement("DIV");a.setAttribute("class","select-selected placeholder-active hover-target");a.innerHTML=selElmnt.options[selElmnt.selectedIndex].innerHTML;customSelects[i].appendChild(a);const b=document.createElement("DIV");b.setAttribute("class","select-items select-hide");for(let j=1;j<selElmnt.length;j+=1){const c=document.createElement("DIV");c.innerHTML=selElmnt.options[j].innerHTML;c.setAttribute("class","hover-target");c.addEventListener("click",function(e){const [s]=this.parentNode.parentNode.getElementsByTagName("select");const h=this.parentNode.previousSibling;for(let k=0;k<s.length;k+=1){if(s.options[k].innerHTML===this.innerHTML){s.selectedIndex=k;h.innerHTML=this.innerHTML;h.classList.remove("placeholder-active");const y=this.parentNode.getElementsByClassName("same-as-selected");for(let l=0;l<y.length;l+=1){y[l].classList.remove("same-as-selected");}this.setAttribute("class","same-as-selected");break;}}h.click();});b.appendChild(c);}customSelects[i].appendChild(b);a.addEventListener("click",function(e){e.stopPropagation();closeAllSelect(this);this.nextSibling.classList.toggle("select-hide");this.classList.toggle("select-arrow-active");});}function closeAllSelect(elmnt){const x=document.getElementsByClassName("select-items");const y=document.getElementsByClassName("select-selected");const arrNo=[];for(let i=0;i<y.length;i+=1){if(elmnt===y[i]){arrNo.push(i)}else{y[i].classList.remove("select-arrow-active");}}for(let i=0;i<x.length;i+=1){if(arrNo.indexOf(i)===-1){x[i].classList.add("select-hide");}}}document.addEventListener("click",closeAllSelect);});